callExternalApi: function(payload) {
  var attempt = 0;
  var response;
  while (attempt < 2) {
    var request = new sn_ws.RESTMessageV2('External Payment API', 'POST');
    request.setRequestBody(JSON.stringify(payload));
    response = request.execute();
    var status = response.getStatusCode();
    if (status < 500) break;
    attempt++;
  }
  if (response.getStatusCode() >= 500) {
    throw new Error('External API failed after retry: HTTP ' + response.getStatusCode());
  }
  return JSON.parse(response.getBody());
}
